from math import comb
from fractions import Fraction

line = input().split()
N = int(line[0])
P_str = line[1]
P = Fraction(P_str).limit_denominator(10000)

total = comb(N, 3)

for K in range(0, N+1):
    prob = Fraction(0)
    for s in range(0, 4):
        if s > K or (3-s) > (N-K):
            continue
        ways = comb(K, s) * comb(N-K, 3-s)
        if s == 0:
            p_s = Fraction(0)
        elif s == 1:
            p_s = Fraction(1, 2)
        else:
            p_s = Fraction(1)
        prob += Fraction(ways, total) * p_s
    if prob >= P:
        print(K)
        break

